export{supabase,auth,projects,invoices,activities,utils}from './supabase.js';export{ModalManager,renderProjects,renderInvoices,updateInvoiceStats}from './portal-ui.js';export{Toast}from '../services/core-utils.js';export{formatCurrency,formatDate,formatRelativeTime,truncate,escapeHtml}from './portal-utils.js';export{isRequired,isValidEmail,isValidPhone}from './portal-utils.js';export{debounce,throttle,waitForDOM}from './portal-utils.js';export{getStorageItem,setStorageItem,removeStorageItem}from './portal-utils.js';export{DEMO_INVOICES,isDemoMode,getCurrentUser,requireAuth}from './portal-auth.js';export{DEMO_PROJECTS}from './portal-data.js';export{loadProjects,getProjectById}from './portal-data.js';export{loadInvoices,getInvoiceById}from './portal-data.js';export{showProjectDetail,filterProjectsByStatus}from './portal-projects.js';export{showInvoiceDetail,setupInvoiceRealtime}from './portal-invoices.js';export{payInvoiceOnline,downloadInvoicePDF,markInvoiceAsPaid}from './portal-payments.js';export{loadDashboard,loadActivityFeed,loadDeadlines}from './portal-dashboard.js';import{Toast}from '../services/core-utils.js';import{ModalManager}from './portal-ui.js';export const toast=Toast;export const modal=new ModalManager();import{loadProjects as loadProjectsFn}from './portal-projects.js';import{loadInvoices as loadInvoicesFn,setupInvoiceRealtime as setupRealtimeFn}from './portal-invoices.js';import{loadDashboard as loadDashboardFn}from './portal-dashboard.js';if(typeof document!=='undefined'){document.addEventListener('DOMContentLoaded',()=>{const path=window.location.pathname;if(path.includes('projects.html')){const grid=document.getElementById('projectsGrid');if(grid){loadProjectsFn(grid);document.querySelectorAll('.filter-chip').forEach(chip=>{chip.addEventListener('click',()=>{document.querySelectorAll('.filter-chip').forEach(c=>c.classList.remove('active'));chip.classList.add('active');const filterText=chip.textContent.trim();const filterMap={'Tất cả': 'all','Đang chạy': 'active','Hoàn thành': 'completed','Tạm dừng': 'paused'};loadProjectsFn(grid,filterMap[filterText]||'all');});});}}if(path.includes('invoices.html')){const table=document.querySelector('.invoice-table tbody');if(table){loadInvoicesFn(table);setupRealtimeFn(table);}}if(path.includes('dashboard.html')){loadDashboardFn();}});}